ter Studiorum – Università di Bologna", "educations/1/companyId": "43130", "educations/1/companyLink1": "https://www.linkedin.com/school/udemy-alumni/", "educations/1/companyUrn": "urn:li:fsd_company:43130", "educations/1/period/endedOn/month": "0", "educations/1/period/endedOn/year": "0", "educations/1/period/startedOn/month": "0", "educations/1/period/startedOn/year": "2019", "educations/1/subtitle": "Master of Business Administration - MBA, Business Administration and Management, General", "educations/1/title": "Udemy Alumni", "experiences/0/companyName": "Italiano Experience Group", "experiences/0/employmentType": "Self-employed", "experiences/0/jobDescription": "Hospitality, Hotels and Restaurant", "experiences/0/jobLocation": "Krabi, Thailand", "experiences/0/jobStartedOn": "8-2013", "experiences/0/jobStillWorking": "true", "experiences/0/title": "Founder & General Manager", "experiences/1/companyName": "Pizza Pocket", "experiences/1/jobDescription": "Pizza Pocket is a new start-up food on delivery oriented. It is a new model of restaurant called Cloud Kitchen, or Ghost Kitchen, Digital Kitchen etc. The peculiarity is that there is no service in, the food is prepared and packed exclusively for the delivery. Nowadays, we are seeing a big changing in our society, the transition from industrial to a new model of digital society, this is disrupting our way of production, consuming and our lifestyle in general. This process speed up by the pandemic  has brought to an impressive increasing orders of the food on delivery, with the spreading of many platforms speciliazed for delivery and the new concept of restaurant, Cloud Kitchen. In the same time the restaurant industry because many restrictive rules are living a big crisis. With our background of restaurateur, we partecipate the new challenge. Our brand Pizzapocket offer of course original Italian pizza, pasta, salads, snacks, bruschetta and some main course. In the traditional restaurant the floor and the service is maybe more important than the kitchen, in this model we don't have the floor so we are more concentrated to the food preparation and packing with purpose to make it fragrant until the house of the customer. Our goal is to bring our brand to success with the opening of several owned and franchised premises. Today we own 4 branches, 3 in Bangkok and 1 in Krabi.", "experiences/1/jobLocation": "Bangkok Metropolitan Area, Thailand", "experiences/1/jobStartedOn": "5-2019", "experiences/1/jobStillWorking": "true", "experiences/1/title": "Co-Founder", "experiences/2/companyName": "Dott. Agronomo Denis Cavatassi", "experiences/2/jobDescription": "Consultancy in agriculture and environment", "experiences/2/jobEndedOn": "2008", "experiences/2/jobLocation": "Teramo Area, Italy", "experiences/2/jobStartedOn": "2004", "experiences/2/jobStillWorking": "false", "experiences/2/title": "Senior Consultant", "experiences/3/companyId": "38980", "experiences/3/companyIndustry": "Business Consulting and Services", "experiences/3/companyLink1": "https://www.linkedin.com/company/gruppogalgano/", "experiences/3/companyName": "Galgano & Associati", "experiences/3/companySize": "51-200", "experiences/3/companyUrn": "urn:li:fsd_company:38980", "experiences/3/companyWebsite": "https://www.galganogroup.com/", "experiences/3/jobDescription": "Environmental System ISO 14000", "experiences/3/jobEndedOn": "2004", "experiences/3/jobLocation": "Pescara Area, Italy", "experiences/3/jobLocationCountry": "IT", "experiences/3/jobStartedOn": "2001", "experiences/3/jobStillWorking": "false", "experiences/3/logo": "https://media.licdn.com/dms/image/v2/C4D0BAQHAb-9n5_-t8A/company-logo_400_400/company-logo_400_400/0/1662557974845/gruppogalgano_logo?e=1778112000&v=beta&t=r3aM2noVGnTMi0XXPiGWcRsSODyvIcE5_7GCE2ghfpc", "experiences/3/title": "Consultant", "experiences/4/companyId": "11372553", "experiences/4/companyIndustry": "Research Services", "experiences/4/companyLink1": "https://www.linkedin.com/company/r